int jc(int x){return ((!x)?(1):(jc(x-1)*x));}
bool f(){for(int i=1;i<=n;++i)if(a[ans[i]]<b[i])return false;
    return true;
}void in(){
	 cin>>n>>k;
	for(int i=1;i<=n;++i)ans[i]=i;
    for(int i=1;i<=n;++i)cin>>a[i];
    for(int i=1;i<=n;++i)cin>>b[i];
}int main(void){in();
    for(int i=1;i<=jc(n);++i){
        if(f()){print();return false;}
        next_permutation(ans+1,ans+n+1);
    }cout<<"-1";
	return false;
}
